function solve(s: string, order: number[], k: number): number {
    const n = s.length;
    const totalSubstrings = n * (n + 1) / 2;
    if (totalSubstrings < k) {
        return -1;
    }

    let low = 0;
    let high = n - 1;
    let ans = n - 1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const replaced = order.slice(0, mid + 1);
        replaced.sort((a, b) => a - b);

        let invalid = 0;
        const firstSegment = replaced[0];
        if (firstSegment > 0) {
            invalid += Math.floor(firstSegment * (firstSegment + 1) / 2);
        }

        const lastSegment = n - 1 - replaced[replaced.length - 1];
        if (lastSegment > 0) {
