            const gap = replaced[i + 1] - replaced[i] - 1;
            if (gap > 0) {
                invalid += Math.floor(gap * (gap + 1) / 2);
            }
        }

        const valid = totalSubstrings - invalid;
        if (valid >= k) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return ans;
}
